@app.route('/admin/tokens', methods=['POST'])
def create_token():
    data = request.get_json()
    
    if not data or 'client_id' not in data or 'expires_at' not in data:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'Missing required fields'
        }), 400
    
    token = secrets.token_urlsafe(32)
    
    conn = get_db()
    cursor = conn.cursor()
    
    try:
        cursor.execute('''
            INSERT INTO access_tokens (token, client_id, user_id, scope, expires_at)
            VALUES (?, ?, ?, ?, ?)
        ''', (
            token,
            data['client_id'],
            data.get('user_id'),
            data.get('scope', ''),
            data['expires_at']
        ))
        conn.commit()
        conn.close()
        
        return jsonify({
            'access_token': token,
            'token_type': 'Bearer',
            'expires_at': data['expires_at'],
            'scope': data.get('scope', '')
        }), 201
    except sqlite3.IntegrityError:
        conn.close()
        return jsonify({
            'error': 'server_error',
            'error_description': 'Failed to create token'
        }), 500

@app.route('/admin/tokens/<token>', methods=['DELETE'])
def revoke_token(token):
    conn = get_db()
    cursor = conn.cursor()
    cursor.execute('DELETE FROM access_tokens WHERE token = ?', (token,))
    deleted = cursor.rowcount
    conn.commit()
    conn.close()
    
    if deleted:
        return jsonify({'message': 'Token revoked successfully'}), 200
    else:
        return jsonify({'error': 'Token not found'}), 404

